#include <bits/stdc++.h>
using namespace std;

struct DSU {
    vector<int> parent, sz;
    DSU(int n) {
        parent.resize(n);
        sz.resize(n, 1);
        for (int i = 0; i < n; ++i) parent[i] = i;
    }
    int find(int x) {
        while (parent[x] != x) {
            parent[x] = parent[parent[x]];
            x = parent[x];
        }
        return x;
    }
    void unite(int a, int b) {
        a = find(a);
        b = find(b);
        if (a == b) return;
        if (sz[a] < sz[b]) swap(a, b);
        parent[b] = a;
        sz[a] += sz[b];
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int N, M;
    cin >> N >> M;

    // We'll build the graph incrementally and check bipartiteness
    // using DSU with parity (bipartite checking with union-find).
    // Node i (0-indexed) has "parity" relative to its DSU root.
    // We maintain parity[i] = 0 means same color as root, 1 means opposite.

    DSU dsu(N);
    vector<int> parity(N, 0);

    auto find_parity = [&](int x) -> pair<int,int> {
        int p = 0;
        while (dsu.parent[x] != x) {
            p ^= parity[x];
            x = dsu.parent[x];
        }
        return {dsu.find(x), p};
    };

    auto unite_with_parity = [&](int a, int b, int relation) -> bool {
        // relation = 0 if same type (T: both truth or both liar)
        // relation = 1 if different type (L: one truth, one liar)
        auto [ra, pa] = find_parity(a);
        auto [rb, pb] = find_parity(b);

        if (ra == rb) {
            // Check consistency
            // The actual relation between a and b is pa ^ pb
            // It should equal relation
            return (pa ^ pb) == relation;
        }

        // Merge smaller into larger
        if (dsu.sz[ra] < dsu.sz[rb]) {
            swap(ra, rb);
            swap(pa, pb);
            swap(a, b);
        }
        // Attach rb under ra
        dsu.parent[rb] = ra;
        dsu.sz[ra] += dsu.sz[rb];
        // We need: parity[b's path to new root] = pb ^ parity[rb] == relation ^ pa
        // So parity[rb] = pa ^ pb ^ relation
        parity[rb] = pa ^ pb ^ relation;
        return true;
    };

    int answer = 0;
    for (int i = 0; i < M; ++i) {
        int x, y;
        char type;
        cin >> x >> y >> type;
        --x; --y;

        // T -> same type (relation=0), L -> different type (relation=1)
        int relation = (type == 'L') ? 1 : 0;

        if (unite_with_parity(x, y, relation)) {
            answer = i + 1;
        } else {
            break;
        }
    }

    cout << answer << '\n';
    return 0;
}
